6	//! 64-bit warp shuffles (`u64` / `f64`).
7	//!
8	//! PTX `shfl.sync` only moves 32-bit registers — there is no `shfl.sync.*.b64`
9	//! instruction and no 64-bit shuffle intrinsic in LLVM. cuda-oxide therefore
10	//! lowers each 64-bit shuffle to one convergent inline-PTX block that splits the
11	//! value into low/high halves (`mov.b64 {lo, hi}, x`), shuffles each half, and
12	//! reassembles the result. `f64` shuffles reuse the `u64` path via a bitcast.
13	//!
14	//! Three kernels, one per shuffle mode family:
15	//!   1. `shuffle_u64_broadcast` — `idx`: broadcast one lane's `u64` to the warp.
16	//!      The value has distinct high/low 32-bit halves so a reassembly bug shows.
17	//!   2. `shuffle_f64_butterfly_sum` — `bfly`: full-warp `f64` reduction; every
18	//!      lane ends with the warp sum.
19	//!   3. `shuffle_u64_neighbor` — `down`/`up`: read the next / previous lane,
20	//!      with edge lanes keeping their own value (the PTX out-of-range rule).
21	//!
22	//! Build and run with:
23	//!   cargo oxide run shuffle_64
24	
25	use cuda_device::{DisjointSlice, kernel, warp};
26	use cuda_host::cuda_module;
27	
28	/// Lane whose value is broadcast in kernel 1.
29	const SRC_LANE: u32 = 5;
30	/// High-word tag for the broadcast value (distinct from the low word).
31	const TAG: u64 = 0xABCD_0000;
32	/// High half for the neighbor-exchange value.
33	const NEIGHBOR_HI: u64 = 0xDEAD_0000_0000_0000;
34	/// High half for the masked half-warp value.
35	const HALF_HI: u64 = 0xF00D_0000_0000_0000;
36	
37	// =============================================================================
38	// KERNELS
39	// =============================================================================
40	#[cuda_module]
41	mod kernels {
42	    use super::*;
43	
44	    /// `idx` mode: every lane builds a `u64` with *different* high and low words
45	    /// (`(lane << 32) | (TAG + lane)`) then reads lane `SRC_LANE`'s value. If the
46	    /// lo/hi split-and-reassemble were wrong, the halves would not match.
47	    ///
48	    /// Expected (single warp): every entry equals
49	    /// `((SRC_LANE as u64) << 32) | (TAG + SRC_LANE)`.
50	    #[kernel]
51	    pub fn shuffle_u64_broadcast(mut out: DisjointSlice<u64>) {
52	        let lane = warp::lane_id();
53	        let val: u64 = ((lane as u64) << 32) | (TAG + lane as u64);
54	        let got = warp::shuffle_u64(val, SRC_LANE);
55	        unsafe {
56	            *out.get_unchecked_mut(lane as usize) = got;
57	        }
58	    }
59	
60	    /// `bfly` mode on `f64`: a classic butterfly reduction. Each lane seeds
61	    /// `lane + 1` and XOR-shuffles with strides 16,8,4,2,1, so every lane ends
62	    /// with the full-warp sum `1 + 2 + ... + 32 = 528`.
63	    #[kernel]
64	    pub fn shuffle_f64_butterfly_sum(mut out: DisjointSlice<f64>) {
65	        let lane = warp::lane_id();
66	        let mut v = (lane as f64) + 1.0;
67	        v += warp::shuffle_xor_f64(v, 16);
68	        v += warp::shuffle_xor_f64(v, 8);
69	        v += warp::shuffle_xor_f64(v, 4);
70	        v += warp::shuffle_xor_f64(v, 2);
71	        v += warp::shuffle_xor_f64(v, 1);
72	        unsafe {
73	            *out.get_unchecked_mut(lane as usize) = v;
74	        }
75	    }
76	
77	    /// `down`/`up` modes: each lane holds `NEIGHBOR_HI | lane` and reads its
78	    /// upper (`down`, lane+1) and lower (`up`, lane-1) neighbor. The PTX
79	    /// out-of-range rule means lane 31's `down` and lane 0's `up` keep their own
80	    /// value.
81	    #[kernel]
82	    pub fn shuffle_u64_neighbor(mut down_out: DisjointSlice<u64>, mut up_out: DisjointSlice<u64>) {
83	        let lane = warp::lane_id();
84	        let val: u64 = NEIGHBOR_HI | (lane as u64);
85	        let down = warp::shuffle_down_u64(val, 1);
86	        let up = warp::shuffle_up_u64(val, 1);
87	        unsafe {
88	            *down_out.get_unchecked_mut(lane as usize) = down;
89	            *up_out.get_unchecked_mut(lane as usize) = up;
90	        }
91	    }
92	
93	    /// Masked `idx`: the warp splits into two 16-lane halves that each shuffle
94	    /// *independently*. In each divergent branch `active_mask()` yields just that
95	    /// half's membermask, and every member broadcasts its leader's value — lane 0
96	    /// for the lower half, lane 16 for the upper half (src_lane is absolute, not
97	    /// relative to the mask). If the membermask operand were mis-wired, the two
98	    /// halves would bleed into each other.
99	    ///
100	    /// Expected: `out[0..16] == HALF_HI | 0` and `out[16..32] == HALF_HI | 16`.
101	    #[kernel]
102	    pub fn shuffle_u64_halfwarp(mut out: DisjointSlice<u64>) {
103	        let lane = warp::lane_id();
104	        let val: u64 = HALF_HI | (lane as u64);
105	        let got = if lane < 16 {
106	            // Lower half (lanes 0..=15): broadcast lane 0 within this subset.
107	            let mask = warp::active_mask();
108	            warp::shuffle_u64_sync(mask, val, 0)
109	        } else {
110	            // Upper half (lanes 16..=31): broadcast lane 16 within this subset.
111	            let mask = warp::active_mask();
112	            warp::shuffle_u64_sync(mask, val, 16)
113	        };
114	        unsafe {
115	            *out.get_unchecked_mut(lane as usize) = got;
116	        }
117	    }
118	}
119	
120	// =============================================================================
121	// HOST CODE
122	// =============================================================================
123	
124	const WARP: usize = 32;
125	
126	fn main() {
127	    use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
128	
129	    println!("=== 64-bit warp shuffle (u64 / f64) ===\n");
130	
131	    let ctx = CudaContext::new(0).expect("Failed to create CUDA context");
132	    let stream = ctx.default_stream();
133	
134	    let (major, minor) = ctx.compute_capability().expect("compute capability");
135	    println!("GPU Compute Capability: sm_{}{}", major, minor);
136	
137	    let module = ctx
138	        .load_module_from_file("shuffle_64.ptx")
139	        .expect("Failed to load PTX module");
140	    let module = kernels::from_module(module).expect("Failed to initialize typed CUDA module");
141	
142	    // A single warp is enough to demonstrate the shuffle semantics.
143	    let cfg = LaunchConfig {
144	        block_dim: (WARP as u32, 1, 1),
145	        grid_dim: (1, 1, 1),
146	        shared_mem_bytes: 0,
147	    };
148	
149	    let mut failed = false;
150	
151	    // ===== Test 1: u64 broadcast (idx) =====
152	    println!("\n--- Test 1: shuffle_u64 (idx broadcast of lane {SRC_LANE}) ---");
153	    let mut out_dev = DeviceBuffer::<u64>::zeroed(&stream, WARP).unwrap();
154	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
155	    unsafe { module.shuffle_u64_broadcast((stream).as_ref(), cfg, &mut out_dev) }
156	        .expect("Kernel launch failed");
157	    let out = out_dev.to_host_vec(&stream).unwrap();
158	
159	    let want = ((SRC_LANE as u64) << 32) | (TAG + SRC_LANE as u64);
160	    println!("out[0]   = {:#018x} (expected {:#018x})", out[0], want);
161	    println!("out[31]  = {:#018x}", out[31]);
162	    if out.iter().all(|&v| v == want) {
163	        println!("✓ every lane received lane {SRC_LANE}'s full 64-bit value");
164	    } else {
165	        println!("✗ broadcast mismatch (high/low half reassembly bug?)");
166	        failed = true;
167	    }
168	
169	    // ===== Test 2: f64 butterfly reduction (bfly) =====
170	    println!("\n--- Test 2: shuffle_xor_f64 (butterfly sum) ---");
171	    let mut sum_dev = DeviceBuffer::<f64>::zeroed(&stream, WARP).unwrap();
172	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
173	    unsafe { module.shuffle_f64_butterfly_sum((stream).as_ref(), cfg, &mut sum_dev) }
174	        .expect("Kernel launch failed");
175	    let sums = sum_dev.to_host_vec(&stream).unwrap();
176	
177	    let want_sum = (1..=WARP).sum::<usize>() as f64; // 528.0
178	    println!("sum[0]   = {} (expected {})", sums[0], want_sum);
179	    if sums.iter().all(|&v| (v - want_sum).abs() < 1e-9) {
180	        println!("✓ every lane holds the full-warp f64 sum");
181	    } else {
182	        println!("✗ butterfly reduction mismatch!");
183	        failed = true;
184	    }
185	
186	    // ===== Test 3: u64 neighbor exchange (down / up) =====
187	    println!("\n--- Test 3: shuffle_down_u64 / shuffle_up_u64 (delta 1) ---");
188	    let mut down_dev = DeviceBuffer::<u64>::zeroed(&stream, WARP).unwrap();
189	    let mut up_dev = DeviceBuffer::<u64>::zeroed(&stream, WARP).unwrap();
190	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
191	    unsafe { module.shuffle_u64_neighbor((stream).as_ref(), cfg, &mut down_dev, &mut up_dev) }
192	        .expect("Kernel launch failed");
193	    let down = down_dev.to_host_vec(&stream).unwrap();
194	    let up = up_dev.to_host_vec(&stream).unwrap();
195	
196	    // down[L] reads lane L+1; the top lane is out of range and keeps its own value.
197	    let want_down: Vec<u64> = (0..WARP)
198	        .map(|l| NEIGHBOR_HI | (if l + 1 < WARP { l + 1 } else { l }) as u64)
199	        .collect();
200	    // up[L] reads lane L-1; lane 0 is out of range and keeps its own value.
201	    let want_up: Vec<u64> = (0..WARP)
202	        .map(|l| NEIGHBOR_HI | (if l >= 1 { l - 1 } else { l }) as u64)
203	        .collect();
204	
205	    println!(
206	        "down[0]  = {:#018x} (expected {:#018x})",
207	        down[0], want_down[0]
208	    );
209	    println!(
210	        "down[31] = {:#018x} (expected {:#018x}, edge keeps own)",
211	        down[31], want_down[31]
212	    );
213	    println!(
214	        "up[0]    = {:#018x} (expected {:#018x}, edge keeps own)",
215	        up[0], want_up[0]
216	    );
217	    println!(
218	        "up[31]   = {:#018x} (expected {:#018x})",
219	        up[31], want_up[31]
220	    );
221	    if down == want_down && up == want_up {
222	        println!("✓ neighbor exchange shifted 64-bit values correctly");
223	    } else {
224	        println!("✗ neighbor exchange mismatch!");
225	        failed = true;
226	    }
227	
228	    // ===== Test 4: masked half-warp broadcast (subset membermask) =====
229	    println!("\n--- Test 4: shuffle_u64_sync (two independent 16-lane halves) ---");
